using namespace std;

class Solution {
public:
    bool equalFrequency(string word) {
        int freq[26] = {0};
        for (char c : word) {
            freq[c - 'a']++;
        }

        for (int i = 0; i < 26; ++i) {
            if (freq[i] == 0) continue;

            vector<int> temp;
            for (int j = 0; j < 26; ++j) {
                if (j == i) {
                    if (freq[j] == 1) {
                        continue;
                    } else {
                        temp.push_back(freq[j] - 1);
                    }
                } else {
                    if (freq[j] > 0) {
                        temp.push_back(freq[j]);
                    }
                }
            }

            if (temp.empty()) continue;

            bool allSame = true;
            int first = temp[0];
            for (int num : temp) {
                if (num != first) {
                    allSame = false;
                    break;
                }
            }

            if (allSame) {
                return true;
            }
        }

        return false;
    }
};

